      if (targets.length === 0) return;

      setCalcStatus(CalculationStatus.VALIDATING);
      setErrorMsg(null);

      const newVisits = [...visits];
      try {
          for (let i = 0; i < targets.length; i++) {
              const v = targets[i];
              setProgress({ current: i + 1, total: targets.length, message: `${t.msgValidating} ${v.surname}...` });
