          setVisits([]);
          setClients([]);
          setStartTrip(null);
          setReturnTrip(null);
          setSettings({
            startAddress: "Dlouhá 1113, 530 06 Pardubice, Česko",
            currentOdometer: 0,
            departureTime: "08:00:00",
            isStrictMode: false,
            isStartValid: false,
            isDarkMode: true,
            googleApiKey: DEFAULT_DEV_API_KEY,
            cacheExpirationDays: 30,
