      {/* Travel Time */}
      <td className={`px-2 py-1 whitespace-nowrap text-base text-right font-mono ${hasCalc ? resultClass : 'text-gray-300 dark:text-gray-600'}`}>
        {hasCalc ? formatDuration(visit.segmentDuration) : '—'}
