  const [isFirebaseReady, setIsFirebaseReady] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false); // Auth check state

  // Auto-Sync Ref
  const autoSyncTimeout = useRef<ReturnType<typeof setTimeout> | null>(null);
