                 routeLoaded = true;
             }
        }
    }

    if (!routeLoaded) {
        // Priority C: Fallback to last session if nothing else
        const savedVisits = localStorage.getItem('odocalc_visits');
        if (savedVisits) {
            try { setVisits(JSON.parse(savedVisits)); } catch (e) {}
