    if (ready) {
        const unsubscribe = FirebaseService.subscribeAuth((currentUser) => {
            if (currentUser) {
                // User signed in -> Set User -> Start Verification
                setUser(currentUser);
                setIsVerifying(true);
                handleSyncFromCloud(currentUser).catch(err => {
                    console.error("Initial sync unhandled", err);
                    setIsVerifying(false);
                });
            } else {
                // User signed out -> Clear User -> Stop Verification
                setUser(null);
                setIsVerifying(false);
            }
        });
        return () => unsubscribe();
    }
  }, []);

  // Helper to apply cloud data to React State
  const applyCloudData = (data: BackupData) => {
      if (data.clients) setClients(data.clients);
      if (data.settings) {
          setSettings(data.settings);
          // Re-apply API key if needed
          if (data.settings.googleApiKey) {
              setRuntimeApiKey(data.settings.googleApiKey);
              loadGoogleMapsScript(data.settings.googleApiKey)
                  .then(() => setIsApiReady(true))
                  .catch(() => setIsApiReady(false));
          }
