export interface Visit {
  id: string; // Unique ID for React keys and selection tracking
  name: string;
  surname: string;
  address: string;
  order: number;
  visitDuration: number; // Duration of the visit in minutes (service time)
  isSkipped?: boolean; // New field to exclude from calculation
  isAddressValid?: boolean; // New field for instant validation status
  // Calculated fields (optional)
  segmentDistance?: number;
  exactDistanceKm?: number; // Unrounded distance
  segmentDuration?: number; // seconds
  arrivalTime?: string; // Calculated time of arrival (HH:mm:ss)
  totalOdometer?: number;
  // Dynamic compilation fields
  preferredTime?: string; // HH:mm copy from Client for reference
}

export type RepetitionType = 'WEEKLY' | 'DATE' | 'INTERVAL';

export interface VisitRepetition {
  type: RepetitionType;
  daysOfWeek?: number[]; // 0=Sunday, 1=Monday...
  specificDate?: string; // YYYY-MM-DD
  intervalStart?: string; // YYYY-MM-DD
  intervalDays?: number;
}

// Persistent Client (Database entity)
export interface Client {
  id: string;
  name: string;
  surname: string;
  address: string;
  defaultDuration: number;
  email?: string;
  phone?: string;
  notes?: string;
  isAddressValid?: boolean;

  // New Scheduling Fields
  visitStartAt?: string; // HH:mm - Preferred time / Sort order
  visitRepetition?: VisitRepetition;
}

// Persistent Storage for Routes
export interface SavedRoute {
  id: string;
  name: string;
  createdAt: string; // ISO Date string
  visits: Visit[];
  startAddress?: string; // Optional: save start address with route
  startTrip?: StartTrip | null;
  returnTrip?: ReturnTrip | null;
}

// Start trip data (Start of the journey)
export interface StartTrip {
  address: string;
  odometer: number;
}

// Return trip data (End of the journey)
export interface ReturnTrip {
  address: string;
  segmentDistance: number;
  exactDistanceKm?: number; // Unrounded distance
  segmentDuration: number;
  arrivalTime?: string; // Calculated time of arrival back at base
  totalOdometer?: number;
}

export interface AppSettings {
  startAddress: string;
  currentOdometer: number;
  departureTime: string; // HH:mm:ss
  isStrictMode: boolean;
  isStartValid?: boolean; // Track if start address is validated
  isDarkMode: boolean; // Dark mode toggle
  googleApiKey?: string; // User provided API Key (Unencrypted)
  cacheExpirationDays?: number; // Cache expiration in days
  language: 'cs' | 'en'; // Display language
}

export enum CalculationStatus {
  IDLE = 'IDLE',
  VALIDATING = 'VALIDATING',
  ROUTING = 'ROUTING',
  COMPLETE = 'COMPLETE',
  ERROR = 'ERROR'
}

// New Consolidated Session Structure
export interface SessionData {
    stops: Visit[];
    start: StartTrip | null;
    return: ReturnTrip | null;
}

// Payload for Cloud Sync
export interface BackupData {
  clients: Client[];
  settings: AppSettings;
  savedRoutes: SavedRoute[];
  lmod: any; // Cache object
  timestamp: number; // Last modified time

  // Session Data (Synced)
  // Can be legacy Array or new SessionData object
  visits?: SessionData | Visit[]; 

  // Legacy fields (kept optional for importing old backups)
  start?: StartTrip | null;
  return?: ReturnTrip | null;
}

import { initializeApp, FirebaseApp, getApps } from "firebase/app";
import { getAuth, GoogleAuthProvider, signInWithPopup, signOut, User, Auth, onAuthStateChanged } from "firebase/auth";
import { getFirestore, doc, setDoc, getDoc, Firestore } from "firebase/firestore/lite";
import { BackupData, SessionData } from "../types";

// --- HARDCODED CONFIGURATION ---
const firebaseConfig = {
  apiKey: "***REMOVED***",
  authDomain: "proj-visopt.firebaseapp.com",
  projectId: "proj-visopt",
  storageBucket: "proj-visopt.firebasestorage.app",
  messagingSenderId: "1048476373474",
  appId: "1:1048476373474:web:f629e9f83179f98970e9bb"
};

let app: FirebaseApp | undefined;
let auth: Auth | undefined;
let db: Firestore | undefined;

const COLLECTION = "localstorage";

// Initialize immediately
try {
    if (getApps().length > 0) {
        app = getApps()[0];
    } else {
        app = initializeApp(firebaseConfig);
    }

    auth = getAuth(app);
    db = getFirestore(app, "dbvisopt");
    console.log("[Cloud] Firebase initialized");
} catch (e) {
    console.error("[Cloud] Firebase Initialization Failed. Check services/firebaseService.ts config.", e);
}

export const FirebaseService = {

  isConfigured: () => {
      return !!auth && !!db;
  },

  /**
   * Subscribe to auth state changes safely.
   */
  subscribeAuth: (callback: (user: User | null) => void) => {
      if (!auth) {
          console.warn("[Cloud] Subscribe attempted before initialization or invalid config");
          return () => {};
      }
      return onAuthStateChanged(auth, callback);
  },

  signIn: async () => {
    if (!auth) throw new Error("Firebase not initialized. Check console for errors.");
    const provider = new GoogleAuthProvider();
    try {
      await signInWithPopup(auth, provider);
    } catch (error: any) {
      console.error("Firebase Sign In Error", error);
      throw new Error(error.message || "Sign in failed");
    }
  },

  signOut: async () => {
    if (!auth) return;
    try {
      await signOut(auth);
    } catch (error) {
      console.error("Firebase Sign Out Error", error);
    }
  },

  /**
   * Syncs local data to Firestore (Upload)
   */
  syncUp: async (user: User) => {
    if (!user || !user.email || !db) return;

    try {
      const clients = JSON.parse(localStorage.getItem('odocalc_db_clients') || '[]');
      const settings = JSON.parse(localStorage.getItem('odocalc_settings') || '{}');
      const savedRoutes = JSON.parse(localStorage.getItem('odocalc_saved_routes') || '[]');
      const lmod = JSON.parse(localStorage.getItem('odocalc_lmod') || '{}');

      // Load raw visits data - this is now a SessionData object in localStorage
      const visitsRaw = localStorage.getItem('odocalc_visits');
      let sessionData: SessionData | any[] = [];

      if (visitsRaw) {
          try {
              sessionData = JSON.parse(visitsRaw);
          } catch(e) {
              sessionData = [];
          }
      }

      // Fallback for legacy localstorage structure if it wasn't migrated yet
      // (Though App.tsx should migrate it on save)
      if (Array.isArray(sessionData)) {
          const start = JSON.parse(localStorage.getItem('odocalc_start') || 'null');
          const ret = JSON.parse(localStorage.getItem('odocalc_return') || 'null');
          sessionData = {
              stops: sessionData,
              start: start,
              return: ret
          };
      }

      const payload: BackupData = {
        clients,
        settings,
        savedRoutes,
        lmod,
        timestamp: Date.now(),
        // Consolidate Session Data
        visits: sessionData
      };

      await setDoc(doc(db, COLLECTION, user.email), payload);

      // Update local tracking timestamp
      localStorage.setItem('odocalc_last_modified', payload.timestamp.toString());

      console.log(`[Cloud] Synced UP successfully for ${user.email}`);
    } catch (e: any) {
      console.error("[Cloud] Sync UP failed", e);
      const msg = e.message || '';
      if (
          e.code === 'permission-denied' || 
          msg.includes('permission-denied') || 
          msg.includes('Missing or insufficient permissions') ||
          msg.includes('insufficient permissions')
      ) {
          throw new Error("PERMISSION_DENIED");
      }
      throw e;
    }
  },

  /**
   * Syncs Cloud data to Local (Download)
   * Returns true if data was updated, false otherwise.
   */
  syncDown: async (user: User): Promise<{ updated: boolean, data?: BackupData }> => {
    if (!user || !user.email || !db) return { updated: false };

    try {
      const docRef = doc(db, COLLECTION, user.email);
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        const cloudData = docSnap.data() as BackupData;
        const localTs = parseInt(localStorage.getItem('odocalc_last_modified') || '0');

        console.log(`[Cloud] Timestamp Check - Local: ${localTs}, Cloud: ${cloudData.timestamp}`);

        // If Cloud is newer than Local, overwrite Local
        if (cloudData.timestamp > localTs) {
          localStorage.setItem('odocalc_db_clients', JSON.stringify(cloudData.clients || []));
          localStorage.setItem('odocalc_settings', JSON.stringify(cloudData.settings || {}));
          localStorage.setItem('odocalc_saved_routes', JSON.stringify(cloudData.savedRoutes || []));
          localStorage.setItem('odocalc_lmod', JSON.stringify(cloudData.lmod || {}));

          // Restore Session Data (Handle New Object vs Old Array)
          if (cloudData.visits) {
              // If it's the new format (Object with stops/start/return)
              if (!Array.isArray(cloudData.visits) && 'stops' in cloudData.visits) {
                  localStorage.setItem('odocalc_visits', JSON.stringify(cloudData.visits));
                  // Clean up legacy keys
                  localStorage.removeItem('odocalc_start');
                  localStorage.removeItem('odocalc_return');
              } 
              // Legacy Array format from Cloud
              else if (Array.isArray(cloudData.visits)) {
                  // Construct new format locally to enforce migration
                  const sessionData: SessionData = {
                      stops: cloudData.visits as any[],
                      start: cloudData.start || null,
                      return: cloudData.return || null
                  };
                  localStorage.setItem('odocalc_visits', JSON.stringify(sessionData));
                  localStorage.removeItem('odocalc_start');
                  localStorage.removeItem('odocalc_return');
              }
          }

          localStorage.setItem('odocalc_last_modified', cloudData.timestamp.toString());

          console.log(`[Cloud] Synced DOWN successfully. Local updated.`);
          return { updated: true, data: cloudData };
        }
      }
    } catch (e: any) {
      console.error("[Cloud] Sync DOWN failed", e);
      const msg = e.message || '';
      if (
          e.code === 'permission-denied' || 
          msg.includes('permission-denied') || 
          msg.includes('Missing or insufficient permissions') ||
          msg.includes('insufficient permissions')
      ) {
          throw new Error("PERMISSION_DENIED");
      }
      throw e;
    }
    return { updated: false };
  }
};

