let db: Firestore | undefined;

const COLLECTION = "localstorage";

// Initialize immediately
try {
    if (getApps().length > 0) {
        app = getApps()[0];
    } else {
        app = initializeApp(firebaseConfig);
    }

    auth = getAuth(app);
