              setResultMode('standard'); // Default for legacy
          } else {
              // New Object Structure
              setVisits(data.visits.stops || []);
              setStartTrip(data.visits.start || null);
              setReturnTrip(data.visits.return || null);
              setResultMode(data.visits.resultMode || 'standard');
          }
      }
  };

  const handleSyncFromCloud = async (currentUser: User) => {
    setIsSyncing(true);
    try {
        const result = await FirebaseService.syncDown(currentUser);
        if (result.updated && result.data) {
            applyCloudData(result.data);
            // Silent success - visual feedback via spinner only
        }
        // If successful (or no update needed), verification passes
        setIsVerifying(false);
    } catch (e: any) {
        if (e.message === "PERMISSION_DENIED") {
            console.warn("User not authorized for Firestore access.");

            // Auto Logout Logic but show message in UI instead of alert
            setMsgType('warning');
            setMsgTitle("Authorization Error");
            setCompilationInfo("Authorization Failed: You do not have access to the cloud database.");

            await FirebaseService.signOut();
            setUser(null); 
            // The message will persist for a few seconds
            setTimeout(() => setCompilationInfo(null), 5000);
            return;
        } else {
            console.error("Sync down error", e);
            setIsVerifying(false);
        }
    } finally {
        setIsSyncing(false);
    }
  };

  /**
   * Helper to perform a partial sync of specific categories.
   * This corresponds to Scenario 2 (OUT): Only upload changed segments.
   */
  const handlePartialSync = async (categories: SyncCategory[]) => {
      if (!isFirebaseReady || !user || isSyncing) return;

      setIsSyncing(true);
      try {
          // Directly upload the specific category with merge: true
          await FirebaseService.syncUp(user, categories);
      } catch (e: any) {
          if (e.message === "PERMISSION_DENIED") {
              setMsgType('warning');
              setMsgTitle("Access Revoked");
              setCompilationInfo("Sync Failed: Access Denied.");
              await FirebaseService.signOut();
              setUser(null);
              setTimeout(() => setCompilationInfo(null), 5000);
          } else {
              console.error(`Partial sync failed for ${categories.join(',')}`, e);
          }
      } finally {
          setIsSyncing(false);
      }
  };

  /**
   * Manual Trigger (Sync Button) or Check.
   * Checks Cloud first (IN), then Full Upload (OUT) if needed.
   * Prevents redundant FULL uploads if timestamps match.
   */
  const handleFullSyncCheck = async () => {
      if (isSyncing) return; // Prevent concurrent syncs
      if (user) {
          setIsSyncing(true);
          try {
              // 1. Try to sync DOWN first (Check if cloud is newer)
              const downResult = await FirebaseService.syncDown(user);

              if (downResult.updated && downResult.data) {
                  // Cloud was newer! Update local.
                  console.log("[AutoSync] Cloud was newer. Updated local state.");
                  applyCloudData(downResult.data);
              } else if (downResult.synced) {
                  // Timestamps equal. Do nothing.
                  console.log("[AutoSync] In sync. No action needed.");
              } else {
                  // Cloud was NOT newer AND not equal. Local is newer (or no cloud doc). Push changes.
                  console.log("[AutoSync] Local is newer. Pushing changes.");
                  await FirebaseService.syncUp(user);
              }
          } catch (e: any) {
              if (e.message === "PERMISSION_DENIED") {
                  setMsgType('warning');
                  setMsgTitle("Access Revoked");
                  setCompilationInfo("Access Revoked: You no longer have access.");
                  await FirebaseService.signOut();
                  setUser(null);
                  setTimeout(() => setCompilationInfo(null), 5000);
              } else {
                  console.error("Manual sync failed", e);
                  setMsgType('error');
                  setMsgTitle("Sync Error");
                  setCompilationInfo(e.message || "Unknown error during sync");
                  setTimeout(() => setCompilationInfo(null), 5000);
              }
          } finally {
              setIsSyncing(false);
          }
      }
  };

  const handleLogin = async () => {
      if (!isFirebaseReady) {
