        setSettings(loaded);
        currentSettings = loaded;
        setCacheExpirationDays(loaded.cacheExpirationDays);

        if (loaded.googleApiKey) {
            setRuntimeApiKey(loaded.googleApiKey);
            loadGoogleMapsScript(loaded.googleApiKey)
                .then(() => setIsApiReady(true))
                .catch(e => { console.error("API Load Error:", e); setIsApiReady(false); });
        }

      } catch (e) { console.error("Failed to load settings", e); }
    } else {
        if (DEFAULT_DEV_API_KEY) {
            setRuntimeApiKey(DEFAULT_DEV_API_KEY);
            loadGoogleMapsScript(DEFAULT_DEV_API_KEY)
                .then(() => setIsApiReady(true))
                .catch(e => { console.error(e); setIsApiReady(false); });
        }
    }

    // 2. Startup Data Loading Priority:
    // Priority A: Saved Route matching Day Name
    // Priority B: Dynamic compilation from DB
    // Priority C: Last session state (legacy/fallback)

    const savedClientsRaw = localStorage.getItem('odocalc_db_clients');
    let dbClients: Client[] = [];
    if (savedClientsRaw) {
        try { dbClients = JSON.parse(savedClientsRaw); setClients(dbClients); } catch(e) {}
    }

    let routeLoaded = false;
    const currentDayName = getCurrentDayName(currentSettings.language).toLowerCase();
    const savedRoutesRaw = localStorage.getItem('odocalc_saved_routes');

    if (savedRoutesRaw) {
        try {
            const savedRoutes: SavedRoute[] = JSON.parse(savedRoutesRaw);
            // Loose match for user convenience (trim whitespace)
            const dayRoute = savedRoutes.find(r => r.name.trim().toLowerCase() === currentDayName);

            if (dayRoute) {
                console.log(`%c[VisOpt] Priority A: Auto-loading Saved Route: ${dayRoute.name}`, 'color: #d93025; font-weight: bold;');
                setVisits(dayRoute.visits);
                if (dayRoute.startTrip) setStartTrip(dayRoute.startTrip);
                if (dayRoute.returnTrip) setReturnTrip(dayRoute.returnTrip);
                setMsgType('success');
                setMsgTitle(translations[currentSettings.language].savedRoutes);
                setCompilationInfo(`Auto-loaded saved route: ${dayRoute.name}`);
                setTimeout(() => setCompilationInfo(null), 5000);
                routeLoaded = true;
            }
        } catch (e) { console.error("Failed to check saved routes", e); }
    }

    if (!routeLoaded && dbClients.length > 0) {
        // Priority B: Dynamic
        // Check if we already have visits (from legacy load or session restore) to avoid overwriting
        // Actually, logic is: IF no saved route found AND we have clients -> check daily plan
        // However, we check if the session is empty or old

        const lastSessionVisits = localStorage.getItem('odocalc_visits');
        let hasSessionData = false;

        if (lastSessionVisits) {
            try {
                const parsed = JSON.parse(lastSessionVisits);
                // Check if new format (Object) or old (Array)
                if (Array.isArray(parsed)) {
                    hasSessionData = parsed.length > 0;
                } else if (parsed && parsed.stops) {
                    hasSessionData = parsed.stops.length > 0;
                }
            } catch(e) {}
        }

        if (!hasSessionData) {
             console.log("%c[VisOpt] Priority B: Dynamic Compilation", 'color: #1a73e8; font-weight: bold;');
             const dailyRoute = loadDailyPlan(dbClients);
             if (dailyRoute.length > 0) {
                 setVisits(dailyRoute);
                 setMsgType('success');
                 setMsgTitle(translations[currentSettings.language].msgDailyInfo);
                 setCompilationInfo(`${translations[currentSettings.language].msgDailyCompilation}: ${dailyRoute.length}`);
                 setTimeout(() => setCompilationInfo(null), 5000);
                 routeLoaded = true;
             }
        }
    }

    if (!routeLoaded) {
        // Priority C: Fallback to last session if nothing else
        // NEW LOGIC: Support Object-based visits structure in localStorage
        const savedVisitsRaw = localStorage.getItem('odocalc_visits');
        if (savedVisitsRaw) {
            try { 
                const parsed = JSON.parse(savedVisitsRaw);

                if (Array.isArray(parsed)) {
                    // LEGACY SUPPORT: Array format
                    setVisits(parsed);
                    // Try load separate keys
                    const s = localStorage.getItem('odocalc_start');
                    if (s) setStartTrip(JSON.parse(s));
                    const r = localStorage.getItem('odocalc_return');
                    if (r) setReturnTrip(JSON.parse(r));
                } else {
                    // NEW FORMAT: Object { stops: [], start: {}, return: {} }
                    setVisits(parsed.stops || []);
                    setStartTrip(parsed.start || null);
                    setReturnTrip(parsed.return || null);
                    setResultMode(parsed.resultMode || 'standard');
                }
            } catch (e) { console.error("Error loading session", e); }
        }
    }

    // Mark initial load as done after a brief delay
    setTimeout(() => { isInitialLoad.current = false; }, 1000);

  }, []);

  // --- Auto-Sync Effect ---
  // Watches visits, startTrip, and returnTrip for changes and triggers sync after debounce
  useEffect(() => {
      // Don't auto-sync if not logged in or during initial load or during verify
      if (!isFirebaseReady || !user || isSyncing || isVerifying || isInitialLoad.current) return;

      if (autoSyncTimeout.current) clearTimeout(autoSyncTimeout.current);

      autoSyncTimeout.current = setTimeout(() => {
          console.debug("[AutoSync] Triggering sync due to session modification...");
          // Visits/Session changes -> Partial Sync of 'visits'
          handlePartialSync(['visits']);
      }, 2000); // 2 second debounce

      return () => {
          if (autoSyncTimeout.current) clearTimeout(autoSyncTimeout.current);
      };
  }, [visits, startTrip, returnTrip, resultMode]); // Dependencies for auto-sync

  // --- Focus/Visibility Re-Sync Effect ---
  // Triggers sync when user comes back to the tab
  useEffect(() => {
      if (!user) return;

      const performSync = () => {
          // If app is idle and authorized, try to sync down
          if (!isSyncing && !isVerifying) {
              console.log("[AutoSync] App focused/visible, checking for cloud updates...");
              handleFullSyncCheck();
          }
      };

      const onVisibilityChange = () => {
          if (document.visibilityState === 'visible') performSync();
      };

      window.addEventListener('focus', performSync);
      document.addEventListener('visibilitychange', onVisibilityChange);

      return () => {
          window.removeEventListener('focus', performSync);
          document.removeEventListener('visibilitychange', onVisibilityChange);
      };
  }, [user, isSyncing, isVerifying]);

  // --- Persistence Effect (Updated) ---
  useEffect(() => {
    // NEW LOGIC: Consolidate visits, start, and return into one object
    const sessionData: SessionData = {
        stops: visits,
        start: startTrip,
        return: returnTrip,
        resultMode: resultMode
    };

    localStorage.setItem('odocalc_visits', JSON.stringify(sessionData));

    // Cleanup Legacy Keys if they exist
    localStorage.removeItem('odocalc_start');
    localStorage.removeItem('odocalc_return');

    localStorage.setItem('odocalc_settings', JSON.stringify(settings));
    localStorage.setItem('odocalc_db_clients', JSON.stringify(clients));

    if (settings.isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [visits, settings, startTrip, returnTrip, clients, resultMode]);

  useEffect(() => { setDeleteConfirming(false); setPlanReloadConfirming(false); }, [selectedIds]);

  const clearCalculation = (currentList: Visit[] = visits) => {
    const cleared = currentList.map(v => {
        const { segmentDistance, exactDistanceKm, segmentDuration, totalOdometer, arrivalTime, ...rest } = v;
        return rest as Visit;
    });
    setStartTrip(null);
    setReturnTrip(null);
    setCalcStatus(CalculationStatus.IDLE);
    setResultMode('standard'); // Reset mode
    if (isMapOpen) setIsMapOpen(false); 
    return cleared;
  };

  const handleExportDB = () => {
      try {
          const getParsed = (key: string) => {
              const val = localStorage.getItem(key);
              return val ? JSON.parse(val) : null;
          };

          // Helper to get session data robustly
          const getSessionData = (): SessionData => {
              const raw = localStorage.getItem('odocalc_visits');
              if (!raw) return { stops: [], start: null, return: null };
              const parsed = JSON.parse(raw);
              if (Array.isArray(parsed)) {
                   return { stops: parsed, start: getParsed('odocalc_start'), return: getParsed('odocalc_return') };
              }
              return parsed as SessionData;
          };

          const session = getSessionData();

          const exportData = {
              visits: session, // This will be the SessionData object
              clients: getParsed('odocalc_db_clients'),
              settings: getParsed('odocalc_settings'),
              // We omit separate start/return keys in new export format
              // but include them for legacy compat if needed? No, sticking to new format.
              lmod: getParsed('odocalc_lmod'),
              saved_routes: getParsed('odocalc_saved_routes'),
              timestamp: new Date().toISOString()
          };
          const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
          const url = URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = `odocalc-backup-${new Date().toISOString().slice(0,10)}.json`;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          URL.revokeObjectURL(url);
          console.log("Database exported successfully.");
      } catch (err: any) { console.error("Export failed:", err.message); }
  };

  const handleImportDB = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const text = event.target?.result as string;
              const data = JSON.parse(text);
              if (!data.visits && !data.settings) throw new Error("Invalid backup file format");

              if (data.lmod) localStorage.setItem('odocalc_lmod', JSON.stringify(data.lmod));
              if (data.saved_routes) localStorage.setItem('odocalc_saved_routes', JSON.stringify(data.saved_routes));
              if (data.settings) setSettings(data.settings);
              if (data.clients) setClients(data.clients);

              // Handle Session Import (New Object vs Old Array)
              if (data.visits) {
                  if (Array.isArray(data.visits)) {
                      setVisits(data.visits);
                      setStartTrip(data.start || null);
                      setReturnTrip(data.return || null);
                      setResultMode('standard');
                  } else {
                      setVisits(data.visits.stops || []);
                      setStartTrip(data.visits.start || null);
                      setReturnTrip(data.visits.return || null);
                      setResultMode(data.visits.resultMode || 'standard');
                  }
              }

              if (data.settings?.googleApiKey) {
                  setRuntimeApiKey(data.settings.googleApiKey);
                  loadGoogleMapsScript(data.settings.googleApiKey)
                    .then(() => setIsApiReady(true))
                    .catch(() => setIsApiReady(false));
              }
              console.log(t.msgImportSuccess);
              // Trigger sync after manual restore - using Full Sync check
              handleFullSyncCheck();
          } catch (err: any) { console.error(t.msgImportFail, err.message); }
      };
      reader.readAsText(file);
      if (importDbInputRef.current) importDbInputRef.current.value = '';
